func:
let scenario = flow.get("scenario") || "normal";

if (msg.topic) {
  flow.set("scenario", msg.topic);
  node.status({ fill: "blue", shape: "dot", text: `escenario: ${msg.topic}` });
  return null;
}

const byScenario = {
  normal: { wind: 8.2, volt: 48.6, curr: 12.1, vib: 2.4, temp: 54, batt: 75, load: 320 },
  wind_danger: { wind: 23, volt: 48.6, curr: 12.1, vib: 2.4, temp: 54, batt: 75, load: 320 },
  temp_high: { wind: 8.2, volt: 48.6, curr: 12.1, vib: 2.4, temp: 85, batt: 75, load: 320 },
  vibration_high: { wind: 8.2, volt: 48.6, curr: 12.1, vib: 7.0, temp: 54, batt: 75, load: 320 },
  battery_low: { wind: 8.2, volt: 48.6, curr: 12.1, vib: 2.4, temp: 54, batt: 15, load: 320 },
  both_source: { wind: 5.0, volt: 24.0, curr: 5.0, vib: 2.4, temp: 54, batt: 60, load: 350 },
  battery_source: { wind: 1.0, volt: 0.0, curr: 0.0, vib: 2.4, temp: 54, batt: 60, load: 300 }
};

scenario = flow.get("scenario") || scenario;
const base = byScenario[scenario] || byScenario.normal;
const jitter = (v, j) => Number((v + (Math.random() * 2 - 1) * j).toFixed(2));
const clamp = (v, min, max) => Math.max(min, Math.min(max, v));

const state = {
  wind: clamp(jitter(base.wind, 0.2), 0, 30),
  volt: clamp(jitter(base.volt, 0.2), 0, 90),
  curr: clamp(jitter(base.curr, 0.4), 0, 120),
  vib: clamp(jitter(base.vib, 0.1), 0, 15),
  temp: clamp(jitter(base.temp, 0.2), -10, 120),
  batt: clamp(jitter(base.batt, 0.2), 0, 100),
  load: clamp(jitter(base.load, 4), 100, 3000)
};

msg.headers = {
  "Content-Type": "application/json",
  "x-api-key": env.get("INGEST_API_KEY") || "dev-ingest-key"
};

const apiBase = (env.get("API_BASE") || "http://localhost:3000").replace(/\/+$/, "");
msg.url = `${apiBase}/api/v1/readings/ingest`;

msg.payload = {
  deviceId: env.get("DEVICE_ID") || "AE-01",
  farmId: env.get("FARM_ID") || "FARM-01",
  plotId: env.get("PLOT_ID") || "PLOT-01",
  ts: new Date().toISOString(),
  windSpeedMs: state.wind,
  genVoltageV: state.volt,
  genCurrentA: state.curr,
  vibrationRms: state.vib,
  genTempC: state.temp,
  batteryPct: Math.round(state.batt),
  loadPowerW: Math.round(state.load),
  mode: `node-red:${scenario}`
};

node.status({ fill: "green", shape: "dot", text: `enviando: ${scenario}` });
return msg;
